var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"저건 설마...... 그때 그 괴물......?","JPN":"あれはまさか……あの時の化け物……？","ENG":"Isn't that... the monster from before?","TWN":"那個難道是……當時那個怪物……？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"제 6종입니다! 하지만 어떻게 여기에......?!","JPN":"第6種です！　しかし、どうやってここに……！？","ENG":"It's the Category 6! But how did it get here?","TWN":"是第6類！可是，它為什麼會在這裡……？！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"하필 이럴 때...... 현재 전력으로는 승산이 없습니다!","JPN":"よりによってこんなときに……今の戦力じゃ勝ち目はありません！","ENG":"Talk about terrible timing... We don't stand a chance against that thing with what we've got!","TWN":"偏偏在這種時候……以目前的戰力，我們是沒有勝算的！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"대원들, 진정하도록!","JPN":"総員、うろたえるな！","ENG":"Calm yourselves!","TWN":"隊員們，冷靜！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"겉모습에 속지 마라! 모습은 흡사해도 그때 그 괴물과는 다르다!","JPN":"見かけに惑わされるな！\\n姿は酷似していようとも、あれはかつての怪物ではない！","ENG":"Don't be fooled by appearances! It may look similar, but it's not like the monster from before!","TWN":"別被外表所騙了！它的外貌雖然很像 ，但和當時的怪物不一樣！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SHIELD_ADMIN_NAMED_NULL","text":{"KOREA":"확실히...... 6종 침식체가 내뿜던 그 가공할 만한 침식파는 느껴지지 않는군요.","JPN":"言われてみると確かに……第6種侵食体が放っていた\\n凄まじい侵食波を感じ取れません。","ENG":"That's true... I can't feel that formidable Corruption ray that the other Category 6 was emitting.","TWN":"確實……我感覺不到當時6類侵蝕體散發的那股令人恐懼的侵蝕波。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"그렇다면 저건 놈의 열화판이라도 된다는 건가?","JPN":"だったら、あれは奴の劣化版とでもいうのか？","ENG":"Then is that a downgraded version of the one from before?","TWN":"那它是6類的劣化版？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그래 보이는군. 방주의 봉인이 약해진 틈을 타서 나타난 모양이다.","JPN":"どうやらそのようだ。箱舟の封印が弱まった隙をついて現れたらしい。","ENG":"It seems to be the case. It must have appeared when the Ark's seal grew weak.","TWN":"應該是吧，可能是趁著方舟的封印變弱時出現的。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그럼 잘은 몰라도 해볼 만하다는 뜻이지?","JPN":"よくはわからないけど、何とかやり合えそうってことよね？","ENG":"I guess that means we've got a shot?","TWN":"這樣我們對它就算不太清楚，也還是有一拼的價值，對吧？"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그래, 알렉스. 넌 항상 내 뜻을 잘 이해해 주는군.","JPN":"そうだ、アレックス。お前はいつも私の意を汲んでくれるな。","ENG":"Yes, Alex. You always understand me so well.","TWN":"沒錯，雅蕾克絲，妳總是能理解我的意思呢。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"장소도, 싸우는 이유도 다르지만 설욕의 때가 왔다.","JPN":"戦う場所も理由も異なるが、いよいよ雪辱の時は来た。","ENG":"Although we now fight in a different place, for a different reason, our time of reckoning has come.","TWN":"雖然場所和戰鬥的理由不一樣，但雪恥時候到了。"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"놈들에게 우리 전대의 힘을 보여 준다!","JPN":"奴らに我らが戦隊の力を知らしめよ！","ENG":"It is time to show them the might of us Maze Division!","TWN":"讓它們見識一下我們戰隊的力量！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"저들에게, 우리가 꺾이지 않는다는 사실을 가르쳐 주도록!","JPN":"我々は決して挫けぬということを、奴らにわからせてやれ！","ENG":"Show them that nothing can beat us down!","TWN":"讓我們告訴它們，我們是永不屈服的！"},"stage":{"bg":"COUNTERSIDE_GRAVE","bgm":"BATTLE_BOSS_EPIC_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};